+/*
+ * ex_browser_replay.c — Deterministic replay in the browser sandbox
+ *
+ * Demonstrates that the browser profile preserves deterministic replay:
+ *   1. Trace events are emitted for browser-safe operations
+ *   2. Trace digests are identical across repeated runs
+ *   3. Ghost determinism oracle works within the sandbox
+ *   4. Browser profile identity is captured in trace metadata
+ *
+ * The browser sandbox restricts *surfaces* (no filesystem, process,
+ * signal), but deterministic semantics are a universal guarantee
+ * across all profiles — including browser.
+ *
+ * SPDX-License-Identifier: MIT
+ */
+
+#include <asx/asx.h>
+#include <asx/core/ghost.h>
+#include <asx/runtime/browser_boundary.h>
+#include <asx/runtime/profile_compat.h>
+#include <asx/runtime/trace.h>
+#include <stdio.h>
+
+#define IGNORE_RC(expr)                                                                            \
+    do {                                                                                           \
+        asx_status ignore_rc_ = (expr);                                                            \
+        (void)ignore_rc_;                                                                          \
+    } while (0)
+
+static int g_pass = 0;
+static int g_fail = 0;
+
+#define SCENARIO_BEGIN(id)                                                                         \
+    do {                                                                                           \
+        const char *_scenario_id = (id);                                                           \
+        int _scenario_ok = 1;                                                                      \
+    (void)0
+
+#define SCENARIO_CHECK(cond, msg)                                                                  \
+    do {                                                                                           \
+        if (!(cond)) {                                                                             \
+            printf("SCENARIO %s fail %s\n", _scenario_id, (msg));                                  \
+            _scenario_ok = 0;                                                                      \
+            g_fail++;                                                                              \
+            goto _scenario_end;                                                                    \
+        }                                                                                          \
+    } while (0)
+
+#define SCENARIO_END()                                                                             \
+    _scenario_end:                                                                                 \
+    if (_scenario_ok) {                                                                            \
+        printf("SCENARIO %s pass\n", _scenario_id);                                                \
+        g_pass++;                                                                                  \
+    }                                                                                              \
+    }                                                                                              \
+    while (0)
+
+static asx_status poll_complete(void *ud, asx_task_id self) {
+    (void)ud;
+    (void)self;
+    return ASX_OK;
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: browser_replay.trace_in_sandbox
+ *
+ * Runs a region lifecycle in the browser profile and verifies
+ * that trace events are emitted. The trace surface is browser-safe.
+ * ------------------------------------------------------------------- */
+
+static void scenario_trace_in_sandbox(void) {
+    SCENARIO_BEGIN("browser_replay.trace_in_sandbox");
+
+    /* Confirm trace surface is available */
+    SCENARIO_CHECK(asx_surface_gate(ASX_SURFACE_TRACE) == ASX_OK, "trace_available");
+
+    asx_runtime_reset();
+    asx_trace_reset();
+
+    asx_region_id rid;
+    asx_task_id tid;
+    SCENARIO_CHECK(asx_region_open(&rid) == ASX_OK, "region_open");
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_complete, NULL, &tid) == ASX_OK, "spawn");
+
+    asx_budget budget = asx_budget_from_polls(64);
+    SCENARIO_CHECK(asx_region_drain(rid, &budget) == ASX_OK, "drain");
+
+    /* Trace events were emitted */
+    uint32_t count = asx_trace_event_count();
+    SCENARIO_CHECK(count > 0, "events_emitted");
+
+    SCENARIO_END();
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: browser_replay.digest_deterministic
+ *
+ * Two identical lifecycles in the browser profile produce the
+ * same trace digest — proving replay works in the sandbox.
+ * ------------------------------------------------------------------- */
+
+static void scenario_digest_deterministic(void) {
+    SCENARIO_BEGIN("browser_replay.digest_deterministic");
+
+    /* Run 1 */
+    asx_runtime_reset();
+    asx_trace_reset();
+
+    asx_region_id rid;
+    asx_task_id tid;
+    SCENARIO_CHECK(asx_region_open(&rid) == ASX_OK, "r1_region");
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_complete, NULL, &tid) == ASX_OK, "r1_spawn");
+
+    asx_budget budget = asx_budget_from_polls(64);
+    SCENARIO_CHECK(asx_region_drain(rid, &budget) == ASX_OK, "r1_drain");
+
+    uint64_t d1 = asx_trace_digest();
+
+    /* Run 2 (identical) */
+    asx_runtime_reset();
+    asx_trace_reset();
+
+    SCENARIO_CHECK(asx_region_open(&rid) == ASX_OK, "r2_region");
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_complete, NULL, &tid) == ASX_OK, "r2_spawn");
+
+    budget = asx_budget_from_polls(64);
+    SCENARIO_CHECK(asx_region_drain(rid, &budget) == ASX_OK, "r2_drain");
+
+    uint64_t d2 = asx_trace_digest();
+
+    SCENARIO_CHECK(d1 == d2, "digests_match");
+    SCENARIO_CHECK(d1 != 0, "digest_nonzero");
+
+    SCENARIO_END();
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: browser_replay.ghost_in_sandbox
+ *
+ * Ghost monitors (debug invariant checking) work in the browser
+ * profile. The ghost surface is browser-safe.
+ * ------------------------------------------------------------------- */
+
+static void scenario_ghost_in_sandbox(void) {
+    SCENARIO_BEGIN("browser_replay.ghost_in_sandbox");
+
+    /* Confirm ghost surface is available */
+    SCENARIO_CHECK(asx_surface_gate(ASX_SURFACE_GHOST) == ASX_OK, "ghost_available");
+
+    asx_ghost_reset();
+    SCENARIO_CHECK(asx_ghost_violation_count() == 0, "clean_slate");
+
+    /* Determinism oracle works in browser sandbox */
+    asx_ghost_determinism_reset();
+    asx_ghost_determinism_record(42);
+    asx_ghost_determinism_record(99);
+    asx_ghost_determinism_seal();
+
+    /* Replay same sequence */
+    asx_ghost_determinism_record(42);
+    asx_ghost_determinism_record(99);
+
+    uint32_t mismatches = asx_ghost_determinism_check();
+    SCENARIO_CHECK(mismatches == 0, "zero_mismatches");
+
+    SCENARIO_END();
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: browser_replay.profile_in_parity
+ *
+ * The browser profile participates in the parity contract: its
+ * trace digest can be compared against other profiles using the
+ * standard parity API.
+ * ------------------------------------------------------------------- */
+
+static void scenario_profile_parity(void) {
+    SCENARIO_BEGIN("browser_replay.profile_in_parity");
+
+    /* Browser profile is a valid profile ID for parity comparison */
+    asx_parity_result result;
+    uint64_t digest = 0x123456789ABCDEF0ULL;
+
+    int ok = asx_profile_digest_compare(digest, ASX_PROFILE_ID_BROWSER, digest,
+                                        ASX_PROFILE_ID_CORE, &result);
+    SCENARIO_CHECK(ok == 1, "same_digest_passes");
+    SCENARIO_CHECK(result.pass == 1, "parity_holds");
+
+    /* Browser is named in the result */
+    SCENARIO_CHECK(result.profile_a == ASX_PROFILE_ID_BROWSER, "profile_a_browser");
+
+    SCENARIO_END();
+}
+
+int main(void) {
+    scenario_trace_in_sandbox();
+    scenario_digest_deterministic();
+    scenario_ghost_in_sandbox();
+    scenario_profile_parity();
+
+    printf("SCENARIO _summary %s total=%d pass=%d fail=%d\n", g_fail > 0 ? "fail" : "pass",
+           g_pass + g_fail, g_pass, g_fail);
+
+    return g_fail > 0 ? 1 : 0;
+}

@@ -0,0 +1,208 @@
+/*
+ * ex_cancel_drain.c — Cancel-aware task drain with quiescence evidence
+ *
+ * Demonstrates the full cancellation lifecycle:
+ *   1. Spawning a long-running task that cooperates with cancellation
+ *   2. Region drain propagates cancel to all tasks
+ *   3. Task observes cancel via asx_checkpoint() and finalizes
+ *   4. Quiescence evidence decomposes the final state into Q1-Q4
+ *   5. Drain progress snapshot shows task/obligation counters mid-drain
+ *
+ * This is the canonical example for understanding structured cancellation
+ * and the bounded-cleanup guarantee.
+ *
+ * SPDX-License-Identifier: MIT
+ */
+
+#include <asx/asx.h>
+#include <stdio.h>
+
+#define IGNORE_RC(expr)                                                                            \
+    do {                                                                                           \
+        asx_status ignore_rc_ = (expr);                                                            \
+        (void)ignore_rc_;                                                                          \
+    } while (0)
+
+static int g_pass = 0;
+static int g_fail = 0;
+
+#define SCENARIO_BEGIN(id)                                                                         \
+    do {                                                                                           \
+        const char *_scenario_id = (id);                                                           \
+        int _scenario_ok = 1;                                                                      \
+    (void)0
+
+#define SCENARIO_CHECK(cond, msg)                                                                  \
+    do {                                                                                           \
+        if (!(cond)) {                                                                             \
+            printf("SCENARIO %s fail %s\n", _scenario_id, (msg));                                  \
+            _scenario_ok = 0;                                                                      \
+            g_fail++;                                                                              \
+            goto _scenario_end;                                                                    \
+        }                                                                                          \
+    } while (0)
+
+#define SCENARIO_END()                                                                             \
+    _scenario_end:                                                                                 \
+    if (_scenario_ok) {                                                                            \
+        printf("SCENARIO %s pass\n", _scenario_id);                                                \
+        g_pass++;                                                                                  \
+    }                                                                                              \
+    }                                                                                              \
+    while (0)
+
+/* -------------------------------------------------------------------
+ * Task: cancel-aware worker
+ *
+ * Polls indefinitely until it observes cancellation via checkpoint,
+ * then finalizes and completes. This models a long-running operation
+ * (e.g., network listener, data processor) that cooperates with
+ * structured shutdown.
+ * ------------------------------------------------------------------- */
+
+static asx_status poll_cancel_aware(void *ud, asx_task_id self) {
+    asx_checkpoint_result cp;
+    (void)ud;
+
+    if (asx_checkpoint(self, &cp) == ASX_OK && cp.cancelled) {
+        IGNORE_RC(asx_task_finalize(self));
+        return ASX_OK;
+    }
+    return ASX_E_PENDING;
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: cancel_drain.cooperative_shutdown
+ *
+ * A cancel-aware task is drained via region close. The task observes
+ * the cancel signal, finalizes, and the region reaches quiescence.
+ * ------------------------------------------------------------------- */
+
+static void scenario_cooperative_shutdown(void) {
+    SCENARIO_BEGIN("cancel_drain.cooperative_shutdown");
+
+    asx_runtime_reset();
+
+    asx_region_id rid;
+    SCENARIO_CHECK(asx_region_open(&rid) == ASX_OK, "region_open");
+
+    /* Spawn a long-running cancel-aware task */
+    asx_task_id tid;
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_cancel_aware, NULL, &tid) == ASX_OK, "spawn");
+
+    /* Prime the task to RUNNING */
+    asx_budget budget = asx_budget_from_polls(1);
+    IGNORE_RC(asx_scheduler_run(rid, &budget));
+
+    asx_task_state state;
+    SCENARIO_CHECK(asx_task_get_state(tid, &state) == ASX_OK && state == ASX_TASK_RUNNING,
+                   "task_running");
+
+    /* Drain the region — this propagates cancel and runs scheduler */
+    budget = asx_budget_from_polls(64);
+    SCENARIO_CHECK(asx_region_drain(rid, &budget) == ASX_OK, "drain_ok");
+
+    /* Task should be completed via cancel cooperation */
+    SCENARIO_CHECK(asx_task_get_state(tid, &state) == ASX_OK && state == ASX_TASK_COMPLETED,
+                   "task_completed");
+
+    /* Full quiescence */
+    SCENARIO_CHECK(asx_quiescence_check(rid) == ASX_OK, "quiescent");
+
+    SCENARIO_END();
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: cancel_drain.quiescence_evidence
+ *
+ * Uses asx_quiescence_check_detailed() to decompose the final
+ * quiescence state into Q1-Q4 conjuncts, proving each condition
+ * individually.
+ * ------------------------------------------------------------------- */
+
+static void scenario_quiescence_evidence(void) {
+    SCENARIO_BEGIN("cancel_drain.quiescence_evidence");
+
+    asx_runtime_reset();
+
+    asx_region_id rid;
+    SCENARIO_CHECK(asx_region_open(&rid) == ASX_OK, "region_open");
+
+    /* Spawn task and create obligation */
+    asx_task_id tid;
+    asx_obligation_id oid;
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_cancel_aware, NULL, &tid) == ASX_OK, "spawn");
+    SCENARIO_CHECK(asx_obligation_reserve(rid, &oid) == ASX_OK, "reserve_obligation");
+
+    /* Before drain: check detailed report shows not quiescent */
+    asx_quiescence_report report;
+    SCENARIO_CHECK(asx_quiescence_check_detailed(rid, &report) == ASX_OK, "report_before");
+    SCENARIO_CHECK(report.quiescent == 0, "not_quiescent_before");
+
+    /* Resolve obligation and drain */
+    SCENARIO_CHECK(asx_obligation_commit(oid) == ASX_OK, "commit");
+
+    asx_budget budget = asx_budget_from_polls(64);
+    SCENARIO_CHECK(asx_region_drain(rid, &budget) == ASX_OK, "drain_ok");
+
+    /* After drain: all Q1-Q4 conditions should hold */
+    SCENARIO_CHECK(asx_quiescence_check_detailed(rid, &report) == ASX_OK, "report_after");
+    SCENARIO_CHECK(report.quiescent == 1, "quiescent");
+    SCENARIO_CHECK(report.q1_tasks_complete == 1, "q1_tasks_done");
+    SCENARIO_CHECK(report.q2_children_closed == 1, "q2_children_done");
+    SCENARIO_CHECK(report.q3_obligations_resolved == 1, "q3_obligations_done");
+    SCENARIO_CHECK(report.q4_cleanup_drained == 1, "q4_cleanup_done");
+
+    SCENARIO_END();
+}
+
+/* -------------------------------------------------------------------
+ * Scenario: cancel_drain.drain_progress_snapshot
+ *
+ * Uses asx_region_drain_progress() to observe task/obligation
+ * counters at different points in the drain lifecycle.
+ * ------------------------------------------------------------------- */
+
+static void scenario_drain_progress(void) {
+    SCENARIO_BEGIN("cancel_drain.drain_progress_snapshot");
+
+    asx_runtime_reset();
+
+    asx_region_id rid;
+    SCENARIO_CHECK(asx_region_open(&rid) == ASX_OK, "region_open");
+
+    /* Spawn two tasks */
+    asx_task_id t1, t2;
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_cancel_aware, NULL, &t1) == ASX_OK, "spawn_t1");
+    SCENARIO_CHECK(asx_task_spawn(rid, poll_cancel_aware, NULL, &t2) == ASX_OK, "spawn_t2");
+
+    /* Snapshot before drain */
+    asx_drain_progress prog;
+    SCENARIO_CHECK(asx_region_drain_progress(rid, &prog) == ASX_OK, "progress_before");
+    SCENARIO_CHECK(prog.tasks_live == 2, "two_tasks_live");
+    SCENARIO_CHECK(prog.tasks_completed == 0, "zero_completed");
+    SCENARIO_CHECK(prog.region_state == ASX_REGION_OPEN, "state_open");
+
+    /* Drain */
