+static volatile int g_stage;
+
+int main(void) {
+    asx_region_id rid;
+    asx_task_id tid;
+    asx_status st;
+    asx_budget budget;
+
+    g_stage = 1;
+    asx_runtime_reset();
+
+    g_stage = 2;
+    st = asx_region_open(&rid);
+    if (st != ASX_OK) return 1;
