+    g_stage = 4;
+    budget = asx_budget_infinite();
+    st = asx_scheduler_run(rid, &budget);
+    if (st != ASX_OK) return 1;
+
+    g_stage = 5;
+    asx_task_state tstate;
+    st = asx_task_get_state(tid, &tstate);
